begin;

-- Staff/AARO academic planning layer.
-- This keeps study plan versions and lecturer assignment in the database
-- so academic-office staff can update them without changing frontend code.

alter table public.user_profiles
  drop constraint if exists user_profiles_role_check;

alter table public.user_profiles
  add constraint user_profiles_role_check
  check (role in ('student', 'lecturer', 'staff', 'admin'));

update public.user_profiles
set role = 'staff'
where lower(coalesce(email, '')) like 'st%@sc.edu.my'
  and role = 'admin';

create or replace function public.handle_new_user()
returns trigger
language plpgsql
security definer
set search_path = public, pg_catalog
as $$
declare
  normalized_email text;
  email_prefix text;
  assigned_role text;
begin
  normalized_email := lower(trim(coalesce(new.email, '')));

  if normalized_email !~ '^[^@]+@sc\.edu\.my$' then
    raise exception 'Only SUC email addresses ending in @sc.edu.my can register.'
      using errcode = '22023';
  end if;

  email_prefix := split_part(normalized_email, '@', 1);

  if email_prefix like 'st%' then
    assigned_role := 'staff';
  elsif email_prefix like 'lc%' then
    assigned_role := 'lecturer';
  elsif email_prefix like 'd%'
    or email_prefix like 'b%'
    or email_prefix like 'p%' then
    assigned_role := 'student';
  else
    raise exception 'Unable to identify account type from this SUC email. AARO staff emails must start with ST, lecturer emails with LC, and student emails with D, B, or P.'
      using errcode = '22023';
  end if;

  insert into public.user_profiles (
    id,
    email,
    full_name,
    username,
    role
  )
  values (
    new.id,
    normalized_email,
    coalesce(
      nullif(trim(new.raw_user_meta_data->>'full_name'), ''),
      normalized_email
    ),
    nullif(trim(new.raw_user_meta_data->>'username'), ''),
    assigned_role
  );

  return new;
end;
$$;

revoke execute on function public.handle_new_user()
  from public, anon, authenticated;

create table if not exists public.study_plan_versions (
  id uuid primary key default gen_random_uuid(),
  programme_key text not null check (programme_key in ('IT', 'CS', 'BOSE')),
  programme_name text not null,
  level text not null check (level in ('Diploma', 'Bachelor')),
  intake_year integer,
  intake_semester text check (intake_semester in ('A', 'B', 'C')),
  version_code text not null,
  status text not null default 'draft' check (status in ('draft', 'active', 'archived')),
  effective_from_term_code text,
  source_label text,
  notes text,
  created_by uuid references public.user_profiles(id) on delete set null,
  updated_by uuid references public.user_profiles(id) on delete set null,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now(),
  unique (programme_key, intake_year, intake_semester, version_code)
);

alter table public.study_plan_versions
  add column if not exists intake_year integer,
  add column if not exists intake_semester text check (intake_semester in ('A', 'B', 'C'));


create table if not exists public.study_plan_courses (
  id uuid primary key default gen_random_uuid(),
  study_plan_version_id uuid not null references public.study_plan_versions(id) on delete cascade,
  term_code text not null,
  course_code text,
  course_name text not null,
  category text,
  credit_hours integer,
  is_placeholder boolean not null default false,
  position integer not null default 1,
  plan_course_key text not null,
  source_files jsonb not null default '[]'::jsonb,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now(),
  unique (study_plan_version_id, term_code, plan_course_key, position)
);

create index if not exists idx_study_plan_versions_programme
  on public.study_plan_versions(programme_key, level, intake_year, intake_semester, status);
create index if not exists idx_study_plan_courses_version_term
  on public.study_plan_courses(study_plan_version_id, term_code, position);
alter table public.study_plan_versions enable row level security;
alter table public.study_plan_courses enable row level security;
grant select on public.study_plan_versions, public.study_plan_courses
  to authenticated;
grant insert, update, delete on public.study_plan_versions, public.study_plan_courses
  to authenticated;
grant all on public.study_plan_versions, public.study_plan_courses
  to service_role;

drop policy if exists "Authenticated users can view study plan versions"
  on public.study_plan_versions;
create policy "Authenticated users can view study plan versions"
  on public.study_plan_versions for select
  to authenticated
  using (true);

drop policy if exists "AARO staff can manage study plan versions"
  on public.study_plan_versions;
create policy "AARO staff can manage study plan versions"
  on public.study_plan_versions for all
  to authenticated
  using (exists (
      select 1 from public.user_profiles profile
      where profile.id = (select auth.uid())
        and profile.role in ('staff', 'admin')
        and coalesce(profile.is_active, true)
    ))
  with check (exists (
      select 1 from public.user_profiles profile
      where profile.id = (select auth.uid())
        and profile.role in ('staff', 'admin')
        and coalesce(profile.is_active, true)
    ));

drop policy if exists "Authenticated users can view study plan courses"
  on public.study_plan_courses;
create policy "Authenticated users can view study plan courses"
  on public.study_plan_courses for select
  to authenticated
  using (true);

drop policy if exists "AARO staff can manage study plan courses"
  on public.study_plan_courses;
create policy "AARO staff can manage study plan courses"
  on public.study_plan_courses for all
  to authenticated
  using (exists (
      select 1 from public.user_profiles profile
      where profile.id = (select auth.uid())
        and profile.role in ('staff', 'admin')
        and coalesce(profile.is_active, true)
    ))
  with check (exists (
      select 1 from public.user_profiles profile
      where profile.id = (select auth.uid())
        and profile.role in ('staff', 'admin')
        and coalesce(profile.is_active, true)
    ));

