ry":"Core","creditHours":6,"isPlaceholder":false,"sourceFiles":["IT 2026C.xlsx"],"position":1,"planCourseKey":"CSIS3006"}]$study_plan_json$::jsonb) as entry(
    "programmeKey" text,
    "programmeName" text,
    "level" text,
    "intakeYear" integer,
    "intakeSemester" text,
    "termCode" text,
    "courseCode" text,
    "courseName" text,
    "category" text,
    "creditHours" integer,
    "isPlaceholder" boolean,
    "sourceFiles" jsonb,
    "position" integer,
    "planCourseKey" text
  )
), version_rows as (
  select
    "programmeKey" as programme_key,
    max("programmeName") as programme_name,
    "level" as level,
    "intakeYear" as intake_year,
    "intakeSemester" as intake_semester,
    concat("programmeKey", '-', "intakeYear", "intakeSemester", '-imported') as version_code,
    min("termCode") as effective_from_term_code
  from raw_entries
  group by "programmeKey", "level", "intakeYear", "intakeSemester"
)
insert into public.study_plan_versions (
  programme_key,
  programme_name,
  level,
  intake_year,
  intake_semester,
  version_code,
  status,
  effective_from_term_code,
  source_label
)
select
  programme_key,
  programme_name,
  level,
  intake_year,
  intake_semester,
  version_code,
  'active',
  effective_from_term_code,
  'Imported from current CS, IT and BoSE study plan files'
from version_rows
on conflict (programme_key, intake_year, intake_semester, version_code)
do update set
  programme_name = excluded.programme_name,
  level = excluded.level,
  status = 'active',
  effective_from_term_code = excluded.effective_from_term_code,
  source_label = excluded.source_label,
  updated_at = now();

