,"isPlaceholder":false,"sourceFiles":["IT 2026C.xlsx"],"position":1,"planCourseKey":"CSIS2073"},{"programmeKey":"IT","programmeName":"Diploma in Information Technology","level":"Diploma","intakeYear":2026,"intakeSemester":"C","termCode":"2028B","courseCode":"CSIS3103","courseName":"Project II","category":"Project","creditHours":3,"isPlaceholder":false,"sourceFiles":["IT 2026C.xlsx"],"position":2,"planCourseKey":"CSIS3103"},{"programmeKey":"IT","programmeName":"Diploma in Information Technology","level":"Diploma","intakeYear":2026,"intakeSemester":"C","termCode":"2028B","courseCode":"CSIS2093","courseName":"Operating System","category":"Core","creditHours":3,"isPlaceholder":false,"sourceFiles":["IT 2026C.xlsx"],"position":3,"planCourseKey":"CSIS2093"},{"programmeKey":"IT","programmeName":"Diploma in Information Technology","level":"Diploma","intakeYear":2026,"intakeSemester":"C","termCode":"2028B","courseCode":"CSIS3033","courseName":"Ethics in Computing","category":"Core","creditHours":3,"isPlaceholder":false,"sourceFiles":["IT 2026C.xlsx"],"position":4,"planCourseKey":"CSIS3033"},{"programmeKey":"IT","programmeName":"Diploma in Information Technology","level":"Diploma","intakeYear":2026,"intakeSemester":"C","termCode":"2028B","courseCode":null,"courseName":"Elective","category":"Elective","creditHours":3,"isPlaceholder":true,"sourceFiles":["IT 2026C.xlsx"],"position":5,"planCourseKey":"PLACEHOLDER-ELECTIVE-3"},{"programmeKey":"IT","programmeName":"Diploma in Information Technology","level":"Diploma","intakeYear":2026,"intakeSemester":"C","termCode":"2028B","courseCode":"PROG2203","courseName":"Human Computer Interaction","category":"Discipline","creditHours":3,"isPlaceholder":false,"sourceFiles":["IT 2026C.xlsx"],"position":6,"planCourseKey":"PROG2203"},{"programmeKey":"IT","programmeName":"Diploma in Information Technology","level":"Diploma","intakeYear":2026,"intakeSemester":"C","termCode":"2028C","courseCode":"CSIS3006","courseName":"Industrial Training","category":"Core","creditHours":6,"isPlaceholder":false,"sourceFiles":["IT 2026C.xlsx"],"position":1,"planCourseKey":"CSIS3006"}]$study_plan_json$::jsonb) as entry(
    "programmeKey" text,
    "programmeName" text,
    "level" text,
    "intakeYear" integer,
    "intakeSemester" text,
    "termCode" text,
    "courseCode" text,
    "courseName" text,
    "category" text,
    "creditHours" integer,
    "isPlaceholder" boolean,
    "sourceFiles" jsonb,
    "position" integer,
    "planCourseKey" text
  )
)
insert into public.study_plan_courses (
  study_plan_version_id,
  term_code,
  course_code,
  course_name,
  category,
  credit_hours,
  is_placeholder,
  position,
  plan_course_key,
  source_files
)
select
  version.id,
  entry."termCode",
  nullif(entry."courseCode", ''),
  entry."courseName",
  nullif(entry."category", ''),
  entry."creditHours",
  coalesce(entry."isPlaceholder", false),
  coalesce(entry."position", 1),
  entry."planCourseKey",
  coalesce(entry."sourceFiles", '[]'::jsonb)
from raw_entries entry
join public.study_plan_versions version
  on version.programme_key = entry."programmeKey"
 and version.intake_year = entry."intakeYear"
 and version.intake_semester = entry."intakeSemester"
 and version.version_code = concat(entry."programmeKey", '-', entry."intakeYear", entry."intakeSemester", '-imported')
on conflict (study_plan_version_id, term_code, plan_course_key, position)
do update set
  course_code = excluded.course_code,
  course_name = excluded.course_name,
  category = excluded.category,
  credit_hours = excluded.credit_hours,
  is_placeholder = excluded.is_placeholder,
  source_files = excluded.source_files,
  updated_at = now();

create or replace function public.staff_assign_course_offering(
  p_course_id uuid,
  p_academic_term_id uuid,
  p_lecturer_id uuid
)
returns uuid
language plpgsql
security definer
set search_path = public
as $$
declare
  actor_id uuid := auth.uid();
  existing_offering_id uuid;
  new_offering_id uuid := gen_random_uuid();
  new_section_code text;
begin
  if actor_id is null or not exists (
    select 1
    from public.user_profiles profile
    where profile.id = actor_id
      and profile.role in ('staff', 'admin')
      and coalesce(profile.is_active, true)
  ) then
    raise exception 'Only AARO staff or administrators can assign classes to lecturers';
  end if;

  if not exists (
    select 1
    from public.user_profiles profile
    where profile.id = p_lecturer_id
      and profile.role = 'lecturer'
      and coalesce(profile.is_active, true)
  ) then
    raise exception 'The selected user is not an active lecturer';
  end if;

  if not exists (select 1 from public.courses course_row where course_row.id = p_course_id) then
    raise exception 'Course template not found';
  end if;

  if not exists (select 1 from public.academic_terms term where term.id = p_academic_term_id) then
    raise exception 'Academic term not found';
  end if;

  select offering.id
    into existing_offering_id
  from public.course_offerings offering
  where offering.course_id = p_course_id
    and offering.academic_term_id = p_academic_term_id
    and offering.owner_id = p_lecturer_id
    and offering.status = 'active'
  limit 1;

  if existing_offering_id is not null then
    insert into public.course_instructors (course_id, user_id)
    values (existing_offering_id, p_lecturer_id)
    on conflict (course_id, user_id) do nothing;
    return existing_offering_id;
  end if;

  new_section_code := upper(substring(replace(new_offering_id::text, '-', ''), 1, 6));

  insert into public.course_offerings (
    id,
    course_id,
    academic_term_id,
    owner_id,
    section_code,
    enrollment_key,
    max_capacity,
    status
  )
  select
    new_offering_id,
    course_row.id,
    p_academic_term_id,
    p_lecturer_id,
    new_section_code,
    upper(substring(md5(new_offering_id::text || clock_timestamp()::text), 1, 8)),
    coalesce(
      case
        when coalesce(to_jsonb(course_row) ->> 'max_capacity', '') ~ '^[0-9]+$'
        then (to_jsonb(course_row) ->> 'max_capacity')::integer
        else null
      end,
      case
        when coalesce(to_jsonb(course_row) ->> 'max_students', '') ~ '^[0-9]+$'
        then (to_jsonb(course_row) ->> 'max_students')::integer
        else null
      end
    ),
    'active'
  from public.courses course_row
  where course_row.id = p_course_id;

  insert into public.course_instructors (course_id, user_id)
  values (new_offering_id, p_lecturer_id)
  on conflict (course_id, user_id) do nothing;

  return new_offering_id;
end;
$$;

revoke all on function public.staff_assign_course_offering(uuid, uuid, uuid)
  from public, anon;
grant execute on function public.staff_assign_course_offering(uuid, uuid, uuid)
  to authenticated, service_role;

notify pgrst, 'reload schema';

commit;
